final:
module top_module(
    input x,
    input b,
    output z
);
    assign z = ~(x & ~b);
endmodule

module J(
    input x,
    input b,
    output z
);
    assign z = ~(x & ~b);
endmodule

module top_module(
    input x,
    input b,
    output z
);
    wire i1_out, i2_out, j1_out, j2_out;
    wire xor_out, nand_out;

    I i1(.x(x), .b(b), .z(i1_out));
    I i2(.x(x), .b(b), .z(i2_out));
    J j1(.x(x), .b(b), .z(j1_out));
    J j2(.x(x), .b(b), .z(j2_out));

    assign xor_out = i1_out ^ j1_out;
    assign nand_out = ~(i2_out & j2_out);

    assign z = xor_out & nand_out;
endmodule
